SELECT

FROM sys_auth_permission
WHERE is_deleted = 0

    AND name LIKE CONCAT('%', #{name}, '%')


    AND type = #{type}


    AND status = #{status}


    AND parent_id = #{parentId}

ORDER BY permission_key ASC

SELECT

FROM sys_auth_permission
WHERE is_deleted = 0

    AND name LIKE CONCAT('%', #{name}, '%')


    AND type = #{type}


    AND status = #{status}


    AND parent_id = #{parentId}

ORDER BY permission_key ASC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM sys_auth_permission
WHERE is_deleted = 0

    AND name LIKE CONCAT('%', #{name}, '%')


    AND type = #{type}


    AND status = #{status}


    AND parent_id = #{parentId}
